    evSebelum: false, evProses: false, evSesudah: false, flashSlot: null,
    pickerOpen: false, pickerField: null, pickerOptions: [], pickerTitle: '',
    showKeypad: false, draftToast: false, submitLoading: false,
    chatMessages: [], chatInput: '', typingIndicator: false, slaSeconds: 7200,
  };

  boqUnits = {
    'Pekerjaan Galian Tanah Biasa': 'm³',
    'Pekerjaan Timbunan Pilihan': 'm³',
    'Pekerjaan Pasangan Batu Kali': 'm³',
    'Pekerjaan Beton K-350': 'm³',
    'Pekerjaan Aspal AC-WC': 'ton',
  };
  boqList = Object.keys(this.boqUnits);
  aktivitasList = ['Penggalian', 'Pengangkutan', 'Pemadatan', 'Pengecoran', 'Pemasangan'];
  lokasiList = ['STA 0+000 – 0+250', 'STA 0+250 – 0+500', 'STA 0+500 – 0+750', 'STA 0+750 – 1+000'];
  cuacaList = [
    { key: 'cerah', label: 'Cerah', color: 'oklch(0.78 0.14 80)' },
    { key: 'mendung', label: 'Mendung', color: 'oklch(0.62 0.01 260)' },
    { key: 'hujan', label: 'Hujan', color: 'oklch(0.55 0.15 250)' },
  ];
  projectList = ['Proyek Jalan Tol Cisumdawu Seksi 3', 'Proyek Bendungan Ciawi', 'Proyek Jembatan Kali Progo'];
  keypadKeys = ['1', '2', '3', '4', '5', '6', '7', '8', '9', '.', '0', 'del'];
  monthsID = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];

  componentDidMount() {
    this.timer = setInterval(() => {
      if (this.state.screen === 'clarification' && this.state.slaSeconds > 0) {
