  setEmail = (e) => this.setState({ email: e.target.value });
  setCatatan = (e) => this.setState({ catatan: e.target.value });
  setChatInput = (e) => this.setState({ chatInput: e.target.value });
  stopPropagation = (e) => e.stopPropagation();

  openPicker = (field, options, title) => this.setState({ pickerOpen: true, pickerField: field, pickerOptions: options, pickerTitle: title });
  closePicker = () => this.setState({ pickerOpen: false });
  selectPickerOption = (val) => this.setState(s => ({ [s.pickerField]: val, pickerOpen: false }));

  startLogin = () => {
    this.setState({ loginLoading: true });
