  };

  goStep = (n) => { if (n < 1 || n > 5) return; this.setState({ step: n }); };
  next = () => this.goStep(this.state.step + 1);
  back = () => this.goStep(this.state.step - 1);

  openKeypad = () => this.setState({ showKeypad: true });
  closeKeypad = () => this.setState({ showKeypad: false });
  keypadPress = (d) => this.setState(s => {
    if (d === 'del') return { volume: s.volume.slice(0, -1) };
    if (d === '.' && s.volume.includes('.')) return {};
    if (s.volume.length > 6) return {};
    return { volume: s.volume + d };
  });

  saveDraft = () => { this.setState({ draftToast: true }); setTimeout(() => this.setState({ draftToast: false }), 1600); };

  toggleEvidence = (slot) => {
    const turningOn = !this.state[slot];
    this.setState({ [slot]: turningOn });
    if (turningOn) {
      this.setState({ flashSlot: slot });
      setTimeout(() => this.setState(s => (s.flashSlot === slot ? { flashSlot: null } : {})), 400);
    }
  };

  submit = () => {
    if (this.state.submitLoading) return;
    this.setState({ submitLoading: true });
    setTimeout(() => {
      const unit = this.boqUnits[this.state.boq] || '';
      const vol = parseFloat(this.state.volume) || 0;
      const avg = Math.max(1, Math.round(vol * 0.52));
      const msg = {
        id: 1, from: 'system', time: '09:12',
        text: `Sistem mendeteksi nilai volume pada item "${this.state.boq || 'item ini'}" (${this.state.volume || 0} ${unit}) berada di luar rata-rata historis STA ini (rata-rata 30 hari terakhir: ${avg} ${unit}). Mohon konfirmasi atau perbaiki nilai.`,
      };
      this.setState({ submitLoading: false, screen: 'success', chatMessages: [msg] });
    }, 1400);
  };

  goClarification = () => this.setState({ screen: 'clarification' });
  backToSuccess = () => this.setState({ screen: 'success' });

  sendChat = () => {
    const text = this.state.chatInput.trim();
    if (!text) return;
    const userMsg = { id: Date.now(), from: 'user', time: 'Baru saja', text };
    this.setState(s => ({ chatMessages: [...s.chatMessages, userMsg], chatInput: '', typingIndicator: true }));
    setTimeout(() => {
      this.setState(s => ({
        typingIndicator: false,
        chatMessages: [...s.chatMessages, { id: Date.now() + 1, from: 'system', time: 'Baru saja', text: 'Terima kasih atas koreksinya. Perubahan dicatat sebagai submission baru (Versi 2) dan akan direview ulang oleh AI.' }],
      }));
    }, 1300);
  };

  restart = () => this.setState({
    screen: 'login', step: 1, email: '', project: '', boq: '', aktivitas: '', lokasi: '', volume: '', cuaca: '', catatan: '',
    evSebelum: false, evProses: false, evSesudah: false, chatMessages: [], chatInput: '', slaSeconds: 7200,
  });

  renderVals() {
    const s = this.state;
    const unit = this.boqUnits[s.boq] || '';
    const step1Done = !!s.boq && !!s.aktivitas;
    const step2Done = !!s.lokasi && !!s.volume && !!s.cuaca;
    const step3Done = s.evSebelum && s.evProses && s.evSesudah;
    const evidenceCount = [s.evSebelum, s.evProses, s.evSesudah].filter(Boolean).length;
    const allRequiredDone = step1Done && step2Done && step3Done;
    const volumeNum = parseFloat(s.volume) || 0;
    const isAnomaly = volumeNum > 150;
    const canProceedMap = { 1: step1Done, 2: step2Done, 3: step3Done, 4: true, 5: allRequiredDone };
    const nextDisabled = !canProceedMap[s.step] || s.submitLoading;
    const progressPct = Math.round((s.step / 5) * 100);
    const sh = Math.floor(s.slaSeconds / 3600), sm = Math.floor((s.slaSeconds % 3600) / 60), ss = s.slaSeconds % 60;

    const pickerOptionsForRender = (s.pickerOptions || []).map(o => {
      const selected = o === s[s.pickerField];
      return { label: o, selected, weight: selected ? 700 : 500, textColor: selected ? 'var(--accent)' : 'var(--text)', onSelect: () => this.selectPickerOption(o) };
    });

    const cuacaChips = this.cuacaList.map(c => {
      const selected = s.cuaca === c.key;
      return {
        key: c.key, label: c.label, color: c.color, selected,
        borderColor: selected ? 'var(--accent)' : 'var(--border)',
        bg: selected ? 'var(--accent-soft)' : '#fff',
        textColor: selected ? 'var(--accent)' : 'var(--text2)',
        onSelect: () => this.setState({ cuaca: c.key }),
      };
    });

    const mkSlot = (key, label, done) => ({
      key, label, done, notDone: !done, flashOpacity: s.flashSlot === key ? 1 : 0,
      statusText: done ? '1 foto · tersimpan' : 'Belum ada foto', statusColor: done ? 'var(--success)' : 'var(--text2)',
      doneWeight: done ? 600 : 500, onTap: () => this.toggleEvidence(key),
    });
    const evidenceSlots = [
      mkSlot('evSebelum', 'Sebelum', s.evSebelum),
      mkSlot('evProses', 'Proses', s.evProses),
      mkSlot('evSesudah', 'Sesudah', s.evSesudah),
    ];

    const mkCheck = (label, ratio, done, onTap) => ({
      label, ratio, done, onTap,
      iconBg: done ? 'var(--success)' : 'transparent', iconBorder: done ? 'var(--success)' : 'var(--border)',
      ratioColor: done ? 'var(--success)' : 'var(--text2)',
