    const checklistItems = [
      mkCheck('Data pekerjaan', `${(s.boq ? 1 : 0) + (s.aktivitas ? 1 : 0)}/2`, step1Done, () => this.goStep(1)),
      mkCheck('Lokasi & volume', `${(s.lokasi ? 1 : 0) + (s.volume ? 1 : 0) + (s.cuaca ? 1 : 0)}/3`, step2Done, () => this.goStep(2)),
      mkCheck('Bukti lapangan', `${evidenceCount}/3`, step3Done, () => this.goStep(3)),
    ];

    const keypadCells = this.keypadKeys.map(k => ({ key: k, label: k === 'del' ? 'Hapus' : k, fontSize: k === 'del' ? '14px' : '20px', onPress: () => this.keypadPress(k) }));

    const chatMessagesForRender = s.chatMessages.map(m => ({
      ...m,
      align: m.from === 'user' ? 'flex-end' : 'flex-start',
      bg: m.from === 'user' ? 'var(--accent)' : 'var(--surface)',
      color: m.from === 'user' ? '#fff' : 'var(--text)',
    }));

    const stepTitles = { 1: 'Info Pekerjaan', 2: 'Lokasi & Volume', 3: 'Bukti Lapangan', 4: 'Catatan', 5: 'Review' };

    return {
      isLogin: s.screen === 'login', isForm: s.screen === 'form', isSuccess: s.screen === 'success', isClarification: s.screen === 'clarification',
      email: s.email, project: s.project, projectLabel: s.project || 'Pilih proyek', projectColor: s.project ? 'var(--text)' : 'var(--text2)', loginLoading: s.loginLoading,
      loginDisabled: !s.email || !s.project || s.loginLoading,
