      loginBtnBg: (!s.email || !s.project || s.loginLoading) ? 'var(--border)' : 'var(--accent)',
      loginBtnColor: (!s.email || !s.project || s.loginLoading) ? 'var(--text2)' : '#fff',
      ctaGlowAnim: (!s.email || !s.project || s.loginLoading) ? 'none' : 'ctaGlow 2.4s ease-in-out infinite',
      setEmail: this.setEmail, setCatatan: this.setCatatan, setChatInput: this.setChatInput, stopPropagation: this.stopPropagation,
      openProject: () => this.openPicker('project', this.projectList, 'Pilih Proyek'),
      openBoq: () => this.openPicker('boq', this.boqList, 'Pilih Item BoQ'),
      openAktivitas: () => this.openPicker('aktivitas', this.aktivitasList, 'Pilih Aktivitas'),
      openLokasi: () => this.openPicker('lokasi', this.lokasiList, 'Pilih Lokasi / STA'),
      startLogin: this.startLogin, todayStr: this.today(),

      step: s.step, stepTitle: stepTitles[s.step], progressPct,
      isStep1: s.step === 1, isStep2: s.step === 2, isStep3: s.step === 3, isStep4: s.step === 4, isStep5: s.step === 5,
      showBack: s.step > 1, goBack: this.back,
      boq: s.boq, boqLabel: s.boq || 'Pilih item BoQ', boqColor: s.boq ? 'var(--text)' : 'var(--text2)',
      aktivitas: s.aktivitas, aktivitasLabel: s.aktivitas || 'Pilih aktivitas', aktivitasColor: s.aktivitas ? 'var(--text)' : 'var(--text2)',
      lokasi: s.lokasi, lokasiLabel: s.lokasi || 'Pilih lokasi / STA', lokasiColor: s.lokasi ? 'var(--text)' : 'var(--text2)',
      unit, volume: s.volume, volumeDisplay: s.volume || '0', volumeColor: s.volume ? 'var(--text)' : 'var(--text2)', catatan: s.catatan,
      cuacaChips, evidenceSlots, evidenceCount, checksumLabel: evidenceCount === 3 ? 'selesai' : 'menunggu',
      openKeypad: this.openKeypad, closeKeypad: this.closeKeypad,
