      typingIndicator: s.typingIndicator,
      slaDisplay: `${this.pad(sh)}:${this.pad(sm)}:${this.pad(ss)}`, slaColor: s.slaSeconds < 600 ? 'var(--danger)' : 'var(--text)',
    };
  }
}
</script>


