import { env } from "cloudflare:workers";
import type { APIRoute } from "astro";

import {
  handleStaticFileRequest,
  type StaticFileMetadata,
  type StaticFileObject,
  type StaticFileStorage,
} from "~/lib/static";

function toStaticFileObject(object: R2Object | R2ObjectBody): StaticFileObject {
  const metadata = object.httpMetadata;
  const result: StaticFileObject = {
    body: "body" in object ? object.body : null,
    httpEtag: object.httpEtag,
    metadata: {
      cacheControl: metadata?.cacheControl ?? "public, max-age=300",
      contentType: metadata?.contentType ?? "application/octet-stream",
    },
    size: object.size,
    uploaded: object.uploaded,
  };
  if (metadata?.contentDisposition) {
    result.metadata.contentDisposition = metadata.contentDisposition;
  }
  if (metadata?.contentEncoding)
    result.metadata.contentEncoding = metadata.contentEncoding;
  if (metadata?.contentLanguage)
    result.metadata.contentLanguage = metadata.contentLanguage;
  return result;
}

function createStorage(bucket: R2Bucket): StaticFileStorage {
  return {
    async delete(key) {
      await bucket.delete(key);
    },
    async get(key) {
      const object = await bucket.get(key);
      return object ? toStaticFileObject(object) : null;
    },
    async head(key) {
      const object = await bucket.head(key);
      return object ? toStaticFileObject(object) : null;
    },
    async put(key, value, metadata: StaticFileMetadata) {
      const object = await bucket.put(key, value, { httpMetadata: metadata });
      return toStaticFileObject(object);
    },
  };
}

function uploadToken(): string | undefined {
  const value: unknown = Reflect.get(env, "STATIC_UPLOAD_TOKEN");
  return typeof value === "string" && value.length > 0 ? value : undefined;
}

const route: APIRoute = ({ params, request }) => {
  return handleStaticFileRequest(
    request,
    params.path,
    createStorage(env.STATIC_FILES),
    uploadToken(),
  );
};

export const GET = route;
export const HEAD = route;
export const POST = route;
export const DELETE = route;
export const ALL = route;
export const MAX_STATIC_FILE_SIZE = 100 * 1024 * 1024;

const DEFAULT_CACHE_CONTROL = "public, max-age=300";
const ALLOWED_METHODS = "GET, HEAD, POST, DELETE";
const MAX_OBJECT_KEY_LENGTH = 1_024;

export interface StaticFileMetadata {
  cacheControl: string;
  contentDisposition?: string;
  contentEncoding?: string;
  contentLanguage?: string;
  contentType: string;
}

export interface StaticFileObject {
  body: ReadableStream<Uint8Array> | null;
  httpEtag: string;
  metadata: StaticFileMetadata;
  size: number;
  uploaded: Date;
}

export interface StaticFileStorage {
  delete(key: string): Promise<void>;
  get(key: string): Promise<StaticFileObject | null>;
  head(key: string): Promise<StaticFileObject | null>;
  put(
    key: string,
    value: ReadableStream<Uint8Array>,
    metadata: StaticFileMetadata,
  ): Promise<StaticFileObject>;
}

class UploadTooLargeError extends Error {}

export async function handleStaticFileRequest(
  request: Request,
  key: string | undefined,
  storage: StaticFileStorage,
  uploadToken: string | undefined,
): Promise<Response> {
  if (!key) return apiError(400, "INVALID_PATH", "A file path is required");
  const pathError = validateObjectKey(key);
  if (pathError) return apiError(400, "INVALID_PATH", pathError);

  try {
    switch (request.method) {
      case "GET":
        return serveObject(await storage.get(key), false);
      case "HEAD":
        return serveObject(await storage.head(key), true);
      case "POST":
        return uploadObject(request, key, storage, uploadToken);
      case "DELETE":
        return deleteObject(request, key, storage, uploadToken);
      default:
        return apiError(405, "METHOD_NOT_ALLOWED", "Method not allowed", {
          Allow: ALLOWED_METHODS,
        });
    }
  } catch (error) {
    if (error instanceof UploadTooLargeError) {
      return apiError(
        413,
        "FILE_TOO_LARGE",
        "Static files are limited to 100 MiB",
      );
    }

    console.error(
      JSON.stringify({
        error: error instanceof Error ? error.message : "Unknown error",
        message: "static file request failed",
        method: request.method,
        path: key,
      }),
    );
    return apiError(500, "INTERNAL_ERROR", "Static file request failed");
  }
}

async function uploadObject(
  request: Request,
  key: string,
  storage: StaticFileStorage,
  uploadToken: string | undefined,
): Promise<Response> {
  const authError = await authorizeMutation(
    request,
    uploadToken,
    "UPLOAD_NOT_CONFIGURED",
    "Static file uploads are not configured",
  );
  if (authError) return authError;

  const contentLength = parseContentLength(
    request.headers.get("content-length"),
  );
  if (contentLength === null) {
    return apiError(
      411,
      "LENGTH_REQUIRED",
      "Content-Length is required for static file uploads",
    );
  }
  if (contentLength > MAX_STATIC_FILE_SIZE) {
    return apiError(
      413,
      "FILE_TOO_LARGE",
      "Static files are limited to 100 MiB",
    );
  }
  if (contentLength === 0 || !request.body) {
    return apiError(
      400,
      "EMPTY_BODY",
      "The request body must contain the file data",
    );
  }

  const metadata = requestMetadata(request.headers);
  // Keep the original request stream: R2 requires its Workers-specific known-length marker.
  const object = await storage.put(key, request.body, metadata);
  const url = new URL(request.url);
  url.search = "";
  url.hash = "";

  return Response.json(
    {
      etag: object.httpEtag,
      path: key,
      size: object.size,
      url: url.toString(),
    },
    {
      status: 201,
      headers: { "Cache-Control": "no-store" },
    },
  );
}

async function deleteObject(
  request: Request,
  key: string,
  storage: StaticFileStorage,
  uploadToken: string | undefined,
): Promise<Response> {
  const authError = await authorizeMutation(
    request,
    uploadToken,
    "DELETE_NOT_CONFIGURED",
    "Static file deletion is not configured",
  );
  if (authError) return authError;

  await storage.delete(key);
  return new Response(null, {
    status: 204,
    headers: { "Cache-Control": "no-store" },
  });
}

async function authorizeMutation(
  request: Request,
  uploadToken: string | undefined,
  unavailableCode: string,
  unavailableMessage: string,
): Promise<Response | null> {
  if (!uploadToken) {
    return apiError(503, unavailableCode, unavailableMessage);
  }

  const authorization = request.headers.get("authorization");
  const providedToken = authorization?.startsWith("Bearer ")
    ? authorization.slice("Bearer ".length)
    : "";
  if (!providedToken || !(await tokensMatch(providedToken, uploadToken))) {
    return apiError(401, "UNAUTHORIZED", "A valid upload token is required", {
      "WWW-Authenticate": "Bearer",
    });
```text
src/
├── components/        React islands and visual components
├── layouts/           Shared document layout and metadata
├── lib/               Stores and utilities
├── pages/             Astro routes and social redirects
└── styles/            Global Tailwind styles

public/                Static assets copied into the Worker bundle
wrangler.jsonc         Cloudflare Worker and static-assets configuration
```

## Static file hosting

Files uploaded to `/static/<path>` are stored in the `leenk-static` R2 bucket and served directly
from the same URL. Reads are public; uploads and deletes require the `STATIC_UPLOAD_TOKEN` Worker
secret. Uploads accept a raw request body up to 100 MiB.

Create the R2 bucket and upload secret once before the first deployment:

```bash
nub exec wrangler r2 bucket create leenk-static
nub exec wrangler secret put STATIC_UPLOAD_TOKEN
```

Upload any binary file while preserving its media type:

```bash
printf 'header = "Authorization: Bearer %s"\n' "$STATIC_UPLOAD_TOKEN" | \
  curl --config - https://www.yusoofsh.id/static/docs/guide.pdf \
    -X POST \
    -H "Content-Type: application/pdf" \
    --data-binary @guide.pdf
```

The same URL supports public `GET` and `HEAD`. Uploading the same path again replaces the existing
file. Authenticated deletion is idempotent and returns `204 No Content`:

```bash
printf 'header = "Authorization: Bearer %s"\n' "$STATIC_UPLOAD_TOKEN" | \
  curl --config - https://www.yusoofsh.id/static/docs/guide.pdf \
    -X DELETE \
    -H "Content-Type: application/octet-stream"
```

## Deployment

The build produces an Astro server entry point and static assets in `dist/`. Preview the exact Worker configuration locally before deploying:

```bash
nub run build
nub run preview
```

Production deployment is intentionally explicit:

```bash
nub run deploy
```

Deploy only after local and CI verification pass. The deploy command changes production state and requires separate approval when run by an agent.

